 6→    public int indexOfTagName(String tagName) {
 7→        if (tagName == null || isEmpty()) {
 8→            return -1;
 9→        }
10→
11→        for (int i = 0; i < size(); i++) {
12→            if (tagName.equals(this.get(i).getTagSlug())) {
13→                return i;
14→            }
15→        }
16→
17→        return -1;
18→    }
19→
20→    private int indexOfTag(ReaderTag tag) {
21→        if (tag == null || isEmpty()) {
22→            return -1;
23→        }
24→
25→        for (int i = 0; i < this.size(); i++) {
26→            if (ReaderTag.isSameTag(tag, this.get(i))) {
27→                return i;
28→            }
29→        }
30→
31→        return -1;
32→    }
33→
34→    public boolean isSameList(ReaderTagList otherList) {
35→        if (otherList == null || otherList.size() != this.size()) {
36→            return false;
37→        }
38→
39→        for (ReaderTag otherTag : otherList) {
40→            int i = this.indexOfTag(otherTag);
41→            if (i == -1) {
42→                return false;
43→            } else if (!otherTag.getEndpoint().equals(this.get(i).getEndpoint())) {
44→                return false;
45→            } else if (!otherTag.getTagTitle().equals(this.get(i).getTagTitle())) {
46→                return false;
47→            }
48→        }
49→
50→        return true;
51→    }
52→
53→    /*
54→     * returns a list of tags that are in this list but not in the passed list
55→     */
56→    public ReaderTagList getDeletions(ReaderTagList otherList) {
57→        ReaderTagList deletions = new ReaderTagList();
58→        if (otherList == null) {
59→            return deletions;
60→        }
61→
62→        for (ReaderTag thisTag : this) {
63→            if (otherList.indexOfTag(thisTag) == -1) {
64→                deletions.add(thisTag);
65→            }
66→        }
67→
68→        return deletions;
69→    }
