/**
 * Checks if this tag is a default blogging prompts tag that is automatically subscribed
 * for new users. These tags should be excluded when determining if the user has selected
 * any interests, so we can show the onboarding flow for new users.
 */
private fun ReaderTag.isBloggingPromptsDefaultTag(): Boolean {
    val slug = tagSlug.lowercase()
    return slug == BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG ||
            slug.startsWith(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_ID_TAG_PREFIX) ||
            slug == BloggingPromptsPostTagProvider.BLOGANUARY_TAG
}"}

